SELECT t.*,
       tt.name AS type_name,
       ts.name AS status_name,
       u.real_name AS creator_name,
       c.name AS college_name
FROM ticket t
LEFT JOIN ticket_type tt ON t.type_id = tt.id
LEFT JOIN ticket_status ts ON t.status_id = ts.id
LEFT JOIN user u ON t.creator_id = u.id
LEFT JOIN college c ON t.college_id = c.id

    AND t.is_deleted = 0

        AND t.type_id = #{typeId}


        AND t.status_id = #{statusId}


        AND t.urgency = #{urgency}


        AND (t.title LIKE CONCAT('%', #{keyword}, '%') OR t.content LIKE CONCAT('%', #{keyword}, '%'))


        AND t.creator_id = #{creatorId}


        AND t.college_id = #{collegeId}


ORDER BY t.create_time DESC
LIMIT #{offset}, #{limit}

